ps.pstext:
if !IsFeatureImplemented(FEAT_SVE_B16B16) then EndOfDecode(Decode_UNDEF); end;
let g : integer = UInt(Pg);
let n : integer = UInt(Zn);
let m : integer = UInt(Zm);
let da : integer = UInt(Zda);
let op1_neg : boolean = FALSE;
let op3_neg : boolean = FALSE;

if IsFeatureImplemented(FEAT_SME2) then CheckSVEEnabled(); else CheckNonStreamingSVEEnabled(); end;
let VL : integer{} = CurrentVL();
let PL : integer{} = VL DIV 8;
let elements : integer = VL DIV 16;
let mask : bits(PL) = P{}(g);
let op1 : bits(VL) = if AnyActiveElement{PL}(mask, 16) then Z{VL}(n) else Zeros{VL};
let op2 : bits(VL) = if AnyActiveElement{PL}(mask, 16) then Z{VL}(m) else Zeros{VL};
let op3 : bits(VL) = Z{}(da);
var result : bits(VL);

for e = 0 to elements-1 do
    if ActivePredicateElement{PL}(mask, e, 16) then
        let elem1 : bits(16) = if op1_neg then BFNeg(op1[e*:16]) else op1[e*:16];
        let elem2 : bits(16) = op2[e*:16];
        let elem3 : bits(16) = if op3_neg then BFNeg(op3[e*:16]) else op3[e*:16];

        result[e*:16] = BFMulAdd(elem3, elem1, elem2, FPCR());
    else
        result[e*:16] = op3[e*:16];

    end;
end;
Z{VL}(da) = result;
